# D1-Skeptic packet-local solution for S39-T1-A-E2
CANON = ["intake", "er", "relation_graph", "features", "model_score", "queue"]

def assess(record: dict) -> str:
    required = {"case_id", "stages", "label_space", "auto_fraud"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    ok = (record["stages"] == list(CANON) and record["label_space"] == "needs_review") and record.get("auto_fraud") is False
    return "PASS" if not (ok) else "REJECT_STAGE_ORDER"

valid = {
    "case_id": "CASO-LIM-039-T1A",
    "stages": list(CANON),
    "label_space": "needs_review",
    "auto_fraud": False,
}
invalid = {**valid, "stages": list(CANON)}
incomplete = {k: v for k, v in valid.items() if k != "label_space"}
print(assess(valid), assess(invalid), assess(incomplete))

# D1-Skeptic packet-local solution for S39-T1-A-E3
CANON = ["intake", "er", "relation_graph", "features", "model_score", "queue"]

def decide(record: dict) -> str:
    if "stages" not in record or record.get("stages") is None:
        return "REQUEST_STAGE_LIST"
    if record.get("er_claims_parentesco") is True:
        return "REJECT_ER_SCOPE"
    if record.get("stages") != list(CANON):
        return "REJECT_STAGE_ORDER"
    if record.get("label_space") != "needs_review" or record.get("auto_fraud") is True:
        return "REJECT_STAGE_ORDER"
    return "CONTINUE"

valid = {"stages": list(CANON), "label_space": "needs_review", "auto_fraud": False, "er_claims_parentesco": False}
bad_order = {**valid, "stages": list(reversed(CANON))}
bad_er = {**valid, "er_claims_parentesco": True}
missing = {"label_space": "needs_review", "auto_fraud": False}
print(decide(valid), decide(bad_order), decide(bad_er), decide(missing))

# D1-Skeptic packet-local solution for S39-T1-B-E2
def assess(record: dict) -> str:
    required = {"name", "ver", "owner", "breaking", "bump"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    ok = (not record["breaking"]) or record["bump"] == "major"
    return "PASS" if ok and bool(record["owner"]) else "REJECT_BUMP_POLICY"

