# D1-Skeptic packet-local solution for S39-T2-A-E3
def decide(packet: dict):
    if "uncertainty" not in packet and packet.get("score") is not None and not packet.get("evidence"):
        return "REQUEST_UNCERTAINTY"
    if packet.get("score") is not None and not packet.get("evidence") and not packet.get("path"):
        return "REJECT_SCORE_ALONE"
    return "CONTINUE"

print(decide({"case_id": "CASO-LIM-039", "score": 0.9, "evidence": ["e1"], "path": ["a","b"], "uncertainty": "low"}))

# D1-Skeptic packet-local solution for S39-T2-B-E2
def assess(record: dict) -> str:
    if record.get("appeal"):
        if not record.get("second_reviewer"):
            return "MISSING:second_reviewer"
        return "reopen"
    auto = "queue" if record["score"] >= record["threshold"] else "skip"
    if record.get("human_action") is not None:
        return "PASS"
    return "PASS" if auto == "queue" else "PASS"

# instruction: auto queue PASS with final queue, override PASS, appeal MISSING:second_reviewer
def assess(record: dict) -> str:
    if record.get("appeal"):
        if "second_reviewer" not in record or not record.get("second_reviewer"):
            return "MISSING:second_reviewer"
        return "PASS"
    auto = "queue" if record["score"] >= record["threshold"] else "skip"
    if record.get("human_action") is not None:
        return "PASS"
    return "PASS"

base = {"case_id": "CASO-LIM-039-T2B", "score": 0.9, "threshold": 0.7, "human_action": None, "appeal": False}
auto_q = dict(base)
override = {**base, "human_action": "skip"}
appeal = {**base, "appeal": True}
print(assess(auto_q), assess(override), assess(appeal))

# D1-Skeptic packet-local solution for S39-T3-A-E2
def assess(c: dict) -> str:
    required = {"pii_minimized", "rbac", "secrets_in_repo", "slice_metrics", "input_limits"}
    missing = sorted(required - c.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    if c.get("secrets_in_repo"):
        return "REJECT_SECRETS"
    if not all(c.get(k) for k in ("pii_minimized", "rbac", "slice_metrics", "input_limits")):
        return "REJECT_SECRETS"
    return "PASS"

