# D1-Skeptic packet-local solution for S39-T3-B-E3
def decide(ops: dict):
    if ops.get("incident"):
        if not ops.get("prev_model_id"):
            return "REQUEST_PREV_MODEL", None
        return "ROLLBACK", ops.get("prev_model_id")
    if ops.get("drift_high"):
        return "MONITOR", "current_model"
    return "STAY", "current_model"

